const body = $json.body || $json;
// Capturar el mensaje y limpiar el formato del teléfono de Twilio
const mensaje = (body.Body || '').toString().trim();
const telefono = (body.From || '').toString().replace('whatsapp:', '').trim();
const usuarioNombre = body.ProfileName || 'Estudiante';

if (!telefono) {
  throw new Error('No se detectó un número de teléfono válido.');
}

return [{
  json: {
    mensaje,
    telefono,
    usuarioNombre
  }
}];

const datosInput = $('Extraer Datos WhatsApp').first().json;

const saludo = `👋 ¡Hola ${datosInput.usuarioNombre}! Bienvenido a *TutorBot* 🤖\n\n`;
const menu = `Por favor, selecciona la materia para tu asesoría ingresando el número correspondiente:\n\n1️⃣ JavaScript\n2️⃣ Python\n3️⃣ Java\n4️⃣ Bases de Datos\n5️⃣ HTML y CSS`;

return [{
  json: {
    telefono: datosInput.telefono,
    respuesta: saludo + menu,
    siguiente_pantalla: 'MENU_MATERIAS'
  }
}];

const msg = $('Extraer Datos WhatsApp').first().json.mensaje;
const telefono = $('Extraer Datos WhatsApp').first().json.telefono;

const materias = {
  "1": "JavaScript",
  "2": "Python",
  "3": "Java",
  "4": "Bases de Datos",
  "5": "HTML y CSS"
};

const materiaSeleccionada = materias[msg];

if (!materiaSeleccionada) {
  return [{
    json: {
      telefono,
      error: true,
      respuesta: "⚠️ Opción no válida. Por favor selecciona un número del 1 al 5 para elegir tu materia.",
      siguiente_pantalla: "MENU_MATERIAS"
    }
  }];
}

return [{
  json: {
    telefono,
    error: false,
    materia_seleccionada: materiaSeleccionada,
    respuesta: `Perfecto 👍\nSeleccionaste: *${materiaSeleccionada}*\n\nBuscando tutores disponibles...`    
  }
}];

const materia = $('Procesar Materia').first().json.materia_seleccionada;
return items.filter(item => 
  item.json.estado === "Activo" && 
  item.json.especialidad_materias === materia
);

const tutoresValidos = $('Filtrar Tutores').all().map(t => t.json.id_tutor);
return items.filter(item => 
  tutoresValidos.includes(item.json.id_tutor) && 
  item.json.estado === "Libre"
);

const diasSemana = {
  "Domingo": 0, "Lunes": 1, "Martes": 2,
  "Miércoles": 3, "Miercoles": 3,
  "Jueves": 4, "Viernes": 5,
  "Sábado": 6, "Sabado": 6
};

function proximaFecha(diaTexto) {
  const hoy = new Date();
  const diaObjetivo = diasSemana[diaTexto];
  if (diaObjetivo === undefined) return null;
  const diaActual = hoy.getDay();
  let diff = diaObjetivo - diaActual;
  if (diff <= 0) diff += 7;
  const res = new Date(hoy);
  res.setDate(hoy.getDate() + diff);
  return res.toISOString().split('T')[0];
}

const tutoresMap = {};
$('Filtrar Tutores').all().forEach(t => {
  tutoresMap[t.json.id_tutor] = t.json.nombre;
});

const opciones = [];
let counter = 1;

for (const dispo of items) {
  const d = dispo.json;
  opciones.push({
    opcion: counter,
    id_tutor: d.id_tutor,
    nombre_tutor: tutoresMap[d.id_tutor] || "Tutor",
    fecha: proximaFecha(d.dia_semana),
    dia_semana: d.dia_semana,
    hora_inicio: d.hora_inicio,
    hora_fin: d.hora_fin
  });
  counter++;
  if (counter > 3) break;
}

return opciones.map(op => ({ json: op }));

const telefono = $('Extraer Datos WhatsApp').first().json.telefono;
return [{
  json: {
    telefono,
    respuesta: "😔 Lo siento, en este momento no tenemos tutores disponibles para la materia solicitada. Por favor, intenta más tarde escribiendo *Hola*.",
    siguiente_pantalla: "NUEVO"
  }
}];

const opciones = items.map(i => i.json);
const materia = $('Procesar Materia').first().json.materia_seleccionada;
const telefono = $('Extraer Datos WhatsApp').first().json.telefono;

let msg = `👨‍🏫 *Opciones de asesoría para ${materia}:*\n\n`;

opciones.forEach(op => {
  msg += `*${op.opcion}*️⃣ ${op.nombre_tutor}\n📅 ${op.fecha} (${op.dia_semana})\n⏰ ${op.hora_inicio} a ${op.hora_fin}\n\n`;
});

msg += "✍️ Responde con el *número* de la opción que desees agendar.";

return [{
  json: {
    telefono,
    respuesta: msg,
    siguiente_pantalla: "ESPERANDO_CONFIRMACION"
  }
}];

const msg = $('Extraer Datos WhatsApp').first().json.mensaje.trim();
const telefono = $('Extraer Datos WhatsApp').first().json.telefono;

const seleccion = parseInt(msg, 10);
const pendientes = items.map(i => i.json);

const reservaElegida = pendientes.find(r => 
  r.id_chat === telefono && 
  parseInt(r.opcion, 10) === seleccion && 
  r.estado === "Pendiente"
);

if (!reservaElegida) {
  return [{
    json: {
      telefono,
      error: true,
      respuesta: "⚠️ Selección inválida. Responde únicamente con el número de la opción elegida (1, 2 o 3).",
      siguiente_pantalla: "ESPERANDO_CONFIRMACION"
    }
  }];
}

return [{
  json: {
    ...reservaElegida,
    error: false
  }
}];

const r = $('Validar Selección').first().json;

let msg = "✅ *¡TU ASESORÍA HA SIDO CONFIRMADA!* 🗓️\n\n";
msg += `👩‍🏫 *Tutor:* ${r.nombre_tutor}\n`;
msg += `📚 *Materia:* ${r.materia}\n`;
msg += `📅 *Fecha:* ${r.fecha} (${r.dia_semana})\n`;
msg += `🕗 *Hora:* ${r.hora_inicio} - ${r.hora_fin}\n\n`;
msg += "Hemos añadido este evento a la agenda. ¡Te esperamos!";

return [{
  json: {
    telefono: r.id_chat,
    respuesta: msg,
    siguiente_pantalla: "NUEVO"
  }
}];

const datosInput = $('Extraer Datos WhatsApp').first().json;

const saludo = `👋 ¡Hola ${datosInput.usuarioNombre}! Bienvenido a *TutorBot* 🤖\n\n`;
const menu = `¿Qué deseas hacer? Responde con el número:\n\n1️⃣ Solicitar una tutoría\n2️⃣ Registrarme como estudiante\n3️⃣ Consultar una tutoría\n4️⃣ Cancelar una tutoría`;

return [{
  json: {
    telefono: datosInput.telefono,
    respuesta: saludo + menu,
    siguiente_pantalla: 'MENU_PRINCIPAL'
  }
}];

const telefono = $('Extraer Datos WhatsApp').first().json.telefono;
const mensaje = ($('Extraer Datos WhatsApp').first().json.mensaje || '').trim();
const mensajeLower = mensaje.toLowerCase();

const sesionRows = $('Buscar Sesión Usuario').all();
const sesionExistente = sesionRows.length > 0 ? sesionRows[0].json : null;

let paso = (sesionExistente && sesionExistente.pantalla_actual === 'REGISTRO')
  ? parseInt(sesionExistente.paso_actual, 10)
  : 0;
if (isNaN(paso)) paso = 0;

let datos = {};
try {
  datos = (sesionExistente && sesionExistente.pantalla_actual === 'REGISTRO' && sesionExistente.datos_parciales)
    ? JSON.parse(sesionExistente.datos_parciales)
    : {};
} catch (e) {
  datos = {};
}

let respuesta = '';
let nuevoPaso = paso;
let pantalla = 'REGISTRO';
let completado = false;

if (paso === 0) {
  nuevoPaso = 1;
  respuesta = '📝 ¡Vamos a registrarte!\n\nPor favor escribe tu nombre completo:';
  datos = {};
}
else if (paso === 1) {
  datos.nombre = mensaje;
  nuevoPaso = 2;
  respuesta = `Gracias, ${datos.nombre} 😊\n\nAhora escribe tu número de documento de identidad:`;
}
else if (paso === 2) {
  datos.documento = mensaje;
  nuevoPaso = 3;
  respuesta = 'Perfecto ✅\n\n¿Qué materia te interesa?\n\n1️⃣ JavaScript\n2️⃣ Python\n3️⃣ Java\n4️⃣ Bases de Datos\n5️⃣ HTML y CSS';
}
else if (paso === 3) {
  const materias = {'1':'JavaScript','2':'Python','3':'Java','4':'Bases de Datos','5':'HTML y CSS'};
  const materiaElegida = materias[mensaje];
  if (!materiaElegida) {
    nuevoPaso = 3;
    respuesta = 'No reconocí esa opción 😅\n\nResponde con un número del 1 al 5.';
  } else {
    datos.materia = materiaElegida;
    nuevoPaso = 4;
    respuesta = `Confirma tus datos 📋\n\n👤 Nombre: ${datos.nombre}\n🪦 Documento: ${datos.documento}\n📚 Materia: ${datos.materia}\n\n¿Es correcto? Responde SI o NO`;
  }
}
else if (paso === 4) {
  if (mensajeLower === 'si' || mensajeLower === 'sí') {
    completado = true;
    nuevoPaso = 0;
    pantalla = 'NUEVO';
    respuesta = `🎉 ¡Registro completado, ${datos.nombre}!\n\nEscribe *menu* para ver las opciones disponibles.`;
  } else if (mensajeLower === 'no') {
    nuevoPaso = 1;
    datos = {};
    respuesta = 'Sin problema, empecemos de nuevo 🔄\n\nEscribe tu nombre completo:';
  } else {
    nuevoPaso = 4;
    respuesta = 'Por favor responde solo SI o NO 🙏';
  }
}

return [{
  json: {
    telefono,
    respuesta,
    siguiente_pantalla: pantalla,
    paso_actual: nuevoPaso,
    datos_parciales: JSON.stringify(datos),
    completado,
    id_estudiante: completado ? telefono : null,
    nombre_estudiante: completado ? datos.nombre : null,
    documento: completado ? datos.documento : null,
    materia_interes: completado ? datos.materia : null,
    fecha_registro: completado ? new Date().toISOString().slice(0,10) : null
  }
}];

const telefono = $('Extraer Datos WhatsApp').first().json.telefono;
return [{
  json: {
    telefono,
    respuesta: '🔍 Escribe el ID de la tutoría que deseas consultar (ejemplo: TU001):',
    siguiente_pantalla: 'CONSULTAR'
  }
}];

const r = $json;
const telefono = $('Extraer Datos WhatsApp').first().json.telefono;
let msg = '✅ *Tutoría encontrada:*\n\n';
msg += `🆔 ID: ${r.id_tutoria}\n`;
msg += `📚 Materia: ${r.materia}\n`;
msg += `📅 Fecha: ${r.fecha}\n`;
msg += `🕗 Hora: ${r.hora}\n`;
msg += `📌 Estado: ${r.estado}\n\n`;
msg += 'Escribe *menu* para volver al inicio.';
return [{ json: { telefono, respuesta: msg, siguiente_pantalla: 'NUEVO' } }];

const telefono = $('Extraer Datos WhatsApp').first().json.telefono;
return [{
  json: {
    telefono,
    respuesta: '⚠️ Tutoría no encontrada. Verifica el ID e intenta de nuevo, o escribe *menu* para volver al inicio.',
    siguiente_pantalla: 'NUEVO'
  }
}];

const telefono = $('Extraer Datos WhatsApp').first().json.telefono;
return [{
  json: {
    telefono,
    respuesta: '❌ Escribe el ID de la tutoría que deseas cancelar (ejemplo: TU001):',
    siguiente_pantalla: 'CANCELAR'
  }
}];

const r = $('Buscar Tutoria (Cancelar)').first().json;
const telefono = $('Extraer Datos WhatsApp').first().json.telefono;
return [{ json: { telefono, respuesta: `✅ Tu tutoría (ID: ${r.id_tutoria}) fue cancelada correctamente.\n\nEscribe *menu* para volver al inicio.`, siguiente_pantalla: 'NUEVO' } }];

const telefono = $('Extraer Datos WhatsApp').first().json.telefono;
return [{
  json: {
    telefono,
    respuesta: '⚠️ Tutoría no encontrada. Verifica el ID e intenta de nuevo, o escribe *menu* para volver al inicio.',
    siguiente_pantalla: 'NUEVO'
  }
}];
